import numpy as np
from collections import deque

def test_hypothesis(inp, out):
    H, W = inp.shape

    # Find 6 position
    pos6 = tuple(np.argwhere(inp == 6)[0])

    # Flood fill from 6 through 8s (and 6 itself)
    visited = set()
    queue = deque([pos6])
    visited.add(pos6)

    while queue:
        r, c = queue.popleft()
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < H and 0 <= nc < W and (nr,nc) not in visited:
                if inp[nr, nc] == 8:
                    visited.add((nr,nc))
                    queue.append((nr,nc))

    # Now build the output
    pred = np.full_like(inp, 8)

    # 1-cells adjacent to visited room are kept
    for r in range(H):
        for c in range(W):
            if inp[r,c] == 1:
                adj_to_room = False
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = r+dr, c+dc
                    if (nr,nc) in visited:
                        adj_to_room = True
                        break
                if adj_to_room:
                    pred[r,c] = 1

    # Room cells adjacent to wall (1 or grid edge) become 7
    for r, c in visited:
        if (r, c) == pos6:
            pred[r,c] = 6
            continue
        is_border = False
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if nr < 0 or nr >= H or nc < 0 or nc >= W:
                is_border = True
                break
            if inp[nr, nc] == 1:
                is_border = True
                break
            if (nr, nc) not in visited and inp[nr, nc] != 1:
                # This shouldn't happen if the flood fill is complete
                pass
        if is_border:
            pred[r,c] = 7
        else:
            pred[r,c] = 8

    return pred

for i, s in enumerate(train_samples):
    inp = np.array(s['input'])
    out = np.array(s['output'])
    pred = test_hypothesis(inp, out)
    match = np.all(pred == out)
    print(f"Example {i}: match={match}")
    if not match:
        diff = pred != out
        print(f"  Diff count: {int(diff.sum())}")
        for r, c in np.argwhere(diff).tolist():
            print(f"  ({r},{c}): pred={int(pred[r,c])} expected={int(out[r,c])}")

