import numpy as np
from collections import deque

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape

    # Find 6 position
    pos6 = tuple(np.argwhere(grid == 6)[0])

    # Flood fill from 6 through non-1 cells (4-connected) to find the "room"
    room = set()
    queue = deque([pos6])
    room.add(pos6)
    while queue:
        r, c = queue.popleft()
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < H and 0 <= nc < W and (nr,nc) not in room and grid[nr,nc] != 1:
                room.add((nr,nc))
                queue.append((nr,nc))

    # Find blue connected components (4-connected)
    blue_cells = set(map(tuple, np.argwhere(grid == 1).tolist()))
    visited_blue = set()
    components = []
    for cell in blue_cells:
        if cell in visited_blue:
            continue
        comp = set()
        q = deque([cell])
        comp.add(cell)
        visited_blue.add(cell)
        while q:
            r, c = q.popleft()
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if (nr,nc) in blue_cells and (nr,nc) not in visited_blue:
                    visited_blue.add((nr,nc))
                    comp.add((nr,nc))
                    q.append((nr,nc))
        components.append(comp)

    # Classify components
    wall_blue = set()
    interior_blue = set()
    for comp in components:
        touches_perimeter = any(r == 0 or r == H-1 or c == 0 or c == W-1 for r,c in comp)
        adj_to_room = any(
            (r+dr, c+dc) in room 
            for r,c in comp 
            for dr,dc in [(-1,0),(1,0),(0,-1),(0,1)]
        )
        if touches_perimeter and adj_to_room:
            wall_blue.update(comp)
        elif adj_to_room:
            interior_blue.update(comp)
        # else: unreachable, removed

    # Build output
    out = np.full_like(grid, 8)

    # Place blue cells
    for r, c in wall_blue:
        out[r, c] = 1
    for r, c in interior_blue:
        out[r, c] = 1

    # Place 6
    out[pos6] = 6

    # For room cells: determine if orange or 8
    for r, c in room:
        if (r, c) == pos6:
            continue
        on_perimeter = (r == 0 or r == H-1 or c == 0 or c == W-1)
        adj_wall_blue = False
        for dr in [-1, 0, 1]:
            for dc in [-1, 0, 1]:
                if dr == 0 and dc == 0:
                    continue
                nr, nc = r+dr, c+dc
                if (nr, nc) in wall_blue:
                    adj_wall_blue = True
                    break
            if adj_wall_blue:
                break

        if on_perimeter or adj_wall_blue:
            out[r, c] = 7
        else:
            out[r, c] = 8

    return out.tolist()

